code = """import json
import re

# Load data
with open(locals()['var_function-call-12757890165530013011'], 'r') as f:
    npm_packages = json.load(f)

with open(locals()['var_function-call-12757890165530013172'], 'r') as f:
    mappings = json.load(f)

with open(locals()['var_function-call-12757890165530013333'], 'r') as f:
    infos = json.load(f)

# Set of (Name, Version) for valid NPM packages (MIT, Release)
valid_packages = set()
for p in npm_packages:
    valid_packages.add((p['Name'], p['Version']))

# Filter mappings to find relevant ProjectNames
# We only care about projects linked to our valid packages
relevant_projects = set()
for m in mappings:
    if (m['Name'], m['Version']) in valid_packages:
        relevant_projects.add(m['ProjectName'])

# Parse project infos
# We need to map ProjectName -> ForkCount
project_forks = {}

# Regex for Project Name
# Samples:
# "The project leaflet/leaflet on GitHub..."
# "The project lberrocal/npm-packages-template is hosted..."
# "The project is hosted on GitHub under the name learnfrontend-dc/product-cart, and..."
# "The GitHub project ledgerproject/keypairoom currently..."
# "The project named leo-ran/easy-node-server is hosted..."
# "The project on GitHub, named leonardparisi/easy-express-server, currently..."

# Strategy: Look for "owner/repo" pattern after specific keywords.
# Or simpler: The project name is usually the only "owner/repo" string in the first part of the sentence?
# Let's try specific patterns.

name_patterns = [
    r"The project ([a-zA-Z0-9_\-\.]+\/[a-zA-Z0-9_\-\.]+) (?:on GitHub|is hosted|has|currently)",
    r"The GitHub project ([a-zA-Z0-9_\-\.]+\/[a-zA-Z0-9_\-\.]+) currently",
    r"The project named ([a-zA-Z0-9_\-\.]+\/[a-zA-Z0-9_\-\.]+) (?:is hosted|currently)",
    r"under the name ([a-zA-Z0-9_\-\.]+\/[a-zA-Z0-9_\-\.]+),",
    r"named ([a-zA-Z0-9_\-\.]+\/[a-zA-Z0-9_\-\.]+), currently"
]

# Regex for Forks
fork_patterns = [
    r"(\d+) forks",
    r"forks count of (\d+)",
    r"forked (\d+) times"
]

def extract_forks(text):
    for p in fork_patterns:
        m = re.search(p, text)
        if m:
            return int(m.group(1).replace(',', ''))
    return 0

def extract_name(text):
    for p in name_patterns:
        m = re.search(p, text)
        if m:
            return m.group(1)
    # Fallback: if "project [owner/repo]" appears
    m = re.search(r"project ([a-zA-Z0-9_\-\.]+\/[a-zA-Z0-9_\-\.]+)", text)
    if m:
        return m.group(1)
    return None

for info in infos:
    text = info.get('Project_Information', '')
    if not text:
        continue
        
    pname = extract_name(text)
    if pname:
        forks = extract_forks(text)
        project_forks[pname] = forks

# Now filter for relevant projects and get top 5
final_list = []
for pname in relevant_projects:
    if pname in project_forks:
        final_list.append({'ProjectName': pname, 'Forks': project_forks[pname]})

# Sort
final_list.sort(key=lambda x: x['Forks'], reverse=True)

print("__RESULT__:")
print(json.dumps(final_list[:10])) # Print top 10 to be safe"""

